<section class="page-heading split"><div><span class="eyebrow blue">Organização dos treinamentos</span><h1>Subcategorias de funções</h1><p>Cadastre funções e tópicos específicos dentro de cada sistema do veículo.</p></div><?php if(can('subcategories','create')): ?><button class="btn primary" data-subcategory-create><i class="bi bi-plus-lg"></i> Nova subcategoria</button><?php endif; ?></section>
<?php if($flash): ?><div class="alert <?= $flash['type']==='success'?'success':'error' ?>"><i class="bi <?= $flash['type']==='success'?'bi-check-circle':'bi-exclamation-circle' ?>"></i> <?= e($flash['message']) ?></div><?php endif; ?>
<section class="panel"><form class="panel-head table-filters" method="get" action="<?= url('subcategorias') ?>"><div class="search"><span><i class="bi bi-search"></i></span><input type="search" name="q" value="<?= e($q) ?>" placeholder="Buscar tópico, função ou sistema..."></div><div class="panel-filters"><select name="categoria"><option value="">Todas as categorias</option><?php foreach($categoryOptions as $option): ?><option value="<?= (int)$option['id'] ?>" <?= $categoryFilter===(int)$option['id']?'selected':'' ?>><?= e($option['nome']) ?></option><?php endforeach; ?></select><select name="status"><option value="">Todas as situações</option><option value="ativo" <?= $status==='ativo'?'selected':'' ?>>Ativas</option><option value="inativo" <?= $status==='inativo'?'selected':'' ?>>Inativas</option></select><button class="btn secondary"><i class="bi bi-search"></i> Buscar</button><?php if($q!==''||$status!==''||$categoryFilter): ?><a class="btn secondary" href="<?= url('subcategorias') ?>" aria-label="Limpar filtros"><i class="bi bi-x-lg"></i></a><?php endif; ?></div></form>
<div class="table-wrap"><table><thead><tr><th>Tópico ou função</th><th>Categoria</th><th>Descrição</th><th>Ordem</th><th>Vídeos</th><th>Situação</th><th>Ações</th></tr></thead><tbody><?php if(!$subcategories): ?><tr><td colspan="7"><div class="table-empty"><i class="bi bi-diagram-3"></i><strong>Nenhuma subcategoria encontrada</strong><span>Cadastre o primeiro tópico de uma categoria.</span></div></td></tr><?php endif; ?><?php foreach($subcategories as $subcategory): ?><tr><td><div class="entity-cell"><?php if($subcategory['imagem']): ?><img src="<?= url($subcategory['imagem']) ?>" alt="Imagem de <?= e($subcategory['nome']) ?>"><?php else: ?><span class="entity-placeholder"><i class="bi bi-diagram-3"></i></span><?php endif; ?><div><strong><?= e($subcategory['nome']) ?></strong><small>Função do veículo</small></div></div></td><td><span class="pill"><?= e($subcategory['categoria_nome']) ?></span></td><td class="description-cell"><?= e($subcategory['descricao']?:'Sem descrição') ?></td><td><?= (int)$subcategory['ordem'] ?></td><td><?= (int)$subcategory['videos'] ?></td><td><span class="status <?= $subcategory['ativo']?'active':'inactive' ?>"><?= $subcategory['ativo']?'Ativa':'Inativa' ?></span></td><td><div class="row-actions"><?php if(can('subcategories','update')): ?><button class="action-btn" data-subcategory-edit data-id="<?= (int)$subcategory['id'] ?>" data-category="<?= (int)$subcategory['categoria_id'] ?>" data-name="<?= e($subcategory['nome']) ?>" data-description="<?= e($subcategory['descricao']) ?>" data-order="<?= (int)$subcategory['ordem'] ?>" data-active="<?= (int)$subcategory['ativo'] ?>" data-image="<?= $subcategory['imagem']?e(url($subcategory['imagem'])):'' ?>" aria-label="Editar <?= e($subcategory['nome']) ?>"><i class="bi bi-pencil"></i></button><?php endif; ?><?php if(can('subcategories','delete')): ?><button class="action-btn danger" data-subcategory-delete data-id="<?= (int)$subcategory['id'] ?>" data-name="<?= e($subcategory['nome']) ?>" aria-label="Excluir <?= e($subcategory['nome']) ?>"><i class="bi bi-trash"></i></button><?php endif; ?></div></td></tr><?php endforeach; ?></tbody></table></div>
<div class="pagination"><form method="get" action="<?= url('subcategorias') ?>" class="per-page"><input type="hidden" name="q" value="<?= e($q) ?>"><input type="hidden" name="status" value="<?= e($status) ?>"><input type="hidden" name="categoria" value="<?= $categoryFilter?:'' ?>"><label>Mostrar <select name="per_page" onchange="this.form.submit()"><?php foreach([5,10,25,50] as $size): ?><option value="<?= $size ?>" <?= $perPage===$size?'selected':'' ?>><?= $size ?></option><?php endforeach; ?></select> linhas</label></form><span>Mostrando <?= $totalRows?$offset+1:0 ?>–<?= min($offset+$perPage,$totalRows) ?> de <?= $totalRows ?></span><nav class="page-buttons" aria-label="Paginação"><?php if($page>1): ?><a href="<?= page_url('subcategorias',['page'=>$page-1]) ?>"><i class="bi bi-chevron-left"></i></a><?php endif; ?><?php for($p=max(1,$page-2);$p<=min($totalPages,$page+2);$p++): ?><a class="<?= $p===$page?'active':'' ?>" href="<?= page_url('subcategorias',['page'=>$p]) ?>"><?= $p ?></a><?php endfor; ?><?php if($page<$totalPages): ?><a href="<?= page_url('subcategorias',['page'=>$page+1]) ?>"><i class="bi bi-chevron-right"></i></a><?php endif; ?></nav></div></section>
<div class="modal" id="subcategory-modal" aria-hidden="true"><div class="modal-dialog"><button class="modal-close" data-modal-close aria-label="Fechar"><i class="bi bi-x-lg"></i></button><div class="modal-content"><span class="eyebrow blue">Função específica</span><h2 data-subcategory-modal-title>Nova subcategoria</h2><p>Vincule o tópico ao sistema correto para organizar os vídeos posteriormente.</p><form method="post" enctype="multipart/form-data" data-subcategory-form><?= csrf_field() ?><input type="hidden" name="action" value="create"><input type="hidden" name="id"><div class="form-grid"><label>Categoria<select name="categoria_id" required><option value="">Selecione o sistema</option><?php foreach($categoryOptions as $option): ?><option value="<?= (int)$option['id'] ?>"><?= e($option['nome']) ?></option><?php endforeach; ?></select></label><label>Nome da subcategoria<input name="nome" maxlength="140" required placeholder="Ex.: Modos ECO, NORMAL e POWER"></label><label class="full">Descrição<textarea name="descricao" rows="4" maxlength="3000" placeholder="Explique a função e o conteúdo que será agrupado"></textarea></label><label>Ordem de exibição<input type="number" name="ordem" min="0" value="0"></label><label class="check"><input type="checkbox" name="ativo" checked> Subcategoria ativa</label><label class="full image-upload"><span class="image-preview" data-subcategory-image-preview><i class="bi bi-image"></i></span><span><strong>Imagem da subcategoria</strong><small>JPG, PNG ou WEBP de até 5 MB</small><input type="file" name="imagem" accept="image/jpeg,image/png,image/webp" data-subcategory-image-input></span></label></div><div class="modal-actions"><button type="button" class="btn secondary" data-modal-close>Cancelar</button><button class="btn primary"><i class="bi bi-check-lg"></i> Salvar subcategoria</button></div></form></div></div></div>
<div class="modal" id="delete-subcategory-modal" aria-hidden="true"><div class="modal-dialog confirm-dialog"><button class="modal-close" data-modal-close aria-label="Fechar"><i class="bi bi-x-lg"></i></button><div class="modal-content"><span class="confirm-icon"><i class="bi bi-trash"></i></span><h2>Excluir subcategoria?</h2><p>Você está prestes a excluir <strong data-delete-subcategory-name></strong>. Subcategorias vinculadas a vídeos não podem ser excluídas.</p><form method="post"><?= csrf_field() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" data-delete-subcategory-id><div class="modal-actions"><button type="button" class="btn secondary" data-modal-close>Cancelar</button><button class="btn danger"><i class="bi bi-trash"></i> Excluir subcategoria</button></div></form></div></div></div>
